"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

interface PageHeaderProps extends React.HTMLAttributes<HTMLDivElement> {
  title: string
  description?: string
  children?: React.ReactNode // Para botões de ação
}

function PageHeader({ title, description, children, className, ...props }: PageHeaderProps) {
  return (
    <div className={cn("flex items-center justify-between", className)} {...props}>
      <div>
        <h1 className="text-xl font-bold text-foreground">{title}</h1>
        {description && (
          <p className="text-sm text-muted-foreground">{description}</p>
        )}
      </div>
      {children && <div className="flex items-center gap-2">{children}</div>}
    </div>
  )
}

interface SectionHeaderProps extends React.HTMLAttributes<HTMLDivElement> {
  title: string
  count?: number
  children?: React.ReactNode // Para botões de ação
}

function SectionHeader({ title, count, children, className, ...props }: SectionHeaderProps) {
  return (
    <div className={cn("flex items-center justify-between", className)} {...props}>
      <h3 className="text-sm font-semibold text-foreground">
        {title}
        {count !== undefined && ` (${count})`}
      </h3>
      {children}
    </div>
  )
}

export { PageHeader, SectionHeader }

