"use client"

import { useState, useCallback, use } from "react"
import { callProposalGeneratorAction } from "@/app/actions/severino"
import { useRouter } from "next/navigation"
import Link from "next/link"
import { useBreadcrumbSetter } from "@/hooks/use-breadcrumb-setter"
import { Download, Target } from "lucide-react"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { useProposals } from "@/contexts/proposals-context"
import { useProjects } from "@/contexts/projects-context"
import { useLeads } from "@/contexts/leads-context"
import { ProposalChatPanel } from "@/components/proposal-chat-panel"
import { ProposalDocument } from "@/components/proposal-document"
import type { ProposalMessage, ProposalInteresse, ProposalModelo } from "@/lib/proposal-types"

const interesseOptions: ProposalInteresse[] = ["Vazio", "Software", "Aplicativo", "Alocacao", "IA"]
const modeloOptions: ProposalModelo[] = ["Vazio", "Escopo Fechado", "Squad Gerenciado", "Body Shop"]

function parseMarkdownToSections(
  markdown: string
): { key: string; title: string; content: string }[] {
  const sections: { key: string; title: string; content: string }[] = []
  const lines = markdown.split("\n")
  let currentTitle = ""
  let currentContent: string[] = []

  for (const line of lines) {
    const h2Match = line.match(/^##\s+(.+)$/)
    const h1Match = line.match(/^#\s+(.+)$/)

    if (h2Match || h1Match) {
      if (currentTitle) {
        const key = currentTitle
          .toLowerCase()
          .normalize("NFD")
          .replace(/[\u0300-\u036f]/g, "")
          .replace(/[^a-z0-9]+/g, "-")
          .replace(/^-|-$/g, "")
        sections.push({ key, title: currentTitle, content: currentContent.join("\n").trim() })
      }
      currentTitle = (h2Match || h1Match)![1].trim()
      currentContent = []
    } else {
      currentContent.push(line)
    }
  }

  if (currentTitle) {
    const key = currentTitle
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-|-$/g, "")
    sections.push({ key, title: currentTitle, content: currentContent.join("\n").trim() })
  }

  return sections
}


export default function ProposalEditorPage({
  params,
}: {
  params: Promise<{ id: string }>
}) {
  const { id } = use(params)
  const router = useRouter()
  const {
    getProposal,
    addMessage,
    setProposalContent,
    updateProposal,
  } = useProposals()

  const { projects, addProject, addKnowledgeBaseFile } = useProjects()
  const { leads } = useLeads()

  const proposal = getProposal(id)

  useBreadcrumbSetter([
    { label: "Gerador de Proposta", href: "/dashboard/gerador-de-proposta" },
    { label: proposal?.nome ?? "Proposta" },
  ])

  const [isProcessing, setIsProcessing] = useState(false)
  const [highlightedSections, setHighlightedSections] = useState<Set<string>>(new Set())
  const [activeTab, setActiveTab] = useState<"chat" | "proposta">("chat")

  const empresa = proposal?.empresa ?? ""
  const para = proposal?.para ?? ""
  const projeto = proposal?.projeto ?? ""
  const interesse = proposal?.interesse ?? "Vazio"
  const modeloTrabalho = proposal?.modeloTrabalho ?? "Vazio"

  // Find linked lead
  const leadOrigem = proposal?.leadOrigemId
    ? leads.find((l) => l.id === proposal.leadOrigemId)
    : undefined

  const handleSendMessage = useCallback(
    async (content: string, fileName?: string) => {
      if (!proposal) return

      const userMsg: ProposalMessage = {
        id: `user-${Date.now()}`,
        role: "user",
        content,
        fileName,
      }
      addMessage(id, userMsg)
      setIsProcessing(true)

      const contextParts: string[] = []
      if (para) contextParts.push(`Cliente: ${para}`)
      if (empresa) contextParts.push(`Empresa: ${empresa}`)
      if (projeto) contextParts.push(`Projeto: ${projeto}`)
      if (interesse && interesse !== "Vazio") contextParts.push(`Interesse/Tipo: ${interesse}`)
      if (modeloTrabalho && modeloTrabalho !== "Vazio") contextParts.push(`Modelo: ${modeloTrabalho}`)
      const context = contextParts.join("\n")

      const apiMessages = [
        ...proposal.conversationHistory.map((m) => ({
          role: m.role,
          content: m.content,
        })),
        { role: "user" as const, content },
      ]

      try {
        const data = await callProposalGeneratorAction({ context, messages: apiMessages, lead_id: proposal.leadOrigemId })

        const aiContent = data.assistant_message || "Resposta recebida."
        const sections = parseMarkdownToSections(aiContent)

        if (data.is_proposal_ready && sections.length > 0) {
          setProposalContent(id, sections)
          const keys = sections.map((s) => s.key)
          setHighlightedSections(new Set(keys))
          setTimeout(() => setHighlightedSections(new Set()), 2000)
          setActiveTab("proposta")

          addMessage(id, {
            id: `ai-${Date.now()}`,
            role: "assistant",
            content: "✅ Proposta comercial gerada com sucesso! Confira o documento ao lado.",
          })
        } else {
          addMessage(id, {
            id: `ai-${Date.now()}`,
            role: "assistant",
            content: aiContent,
          })
        }
      } catch (error) {
        console.error("[proposal-generator] Error:", error)
        addMessage(id, {
          id: `ai-error-${Date.now()}`,
          role: "assistant",
          content: "Desculpe, ocorreu um erro ao processar sua mensagem. Tente novamente.",
        })
      } finally {
        setIsProcessing(false)
      }
    },
    [id, proposal, empresa, para, projeto, interesse, modeloTrabalho, addMessage, setProposalContent]
  )

  function handleMarkConcluida() {
    updateProposal(id, { status: "Concluída" })
    toast.success("Proposta marcada como concluída!")
  }

  function generateJiraKey(name: string): string {
    const words = name.split(/\s+/).filter(Boolean)
    let key = words.map((w) => w[0]?.toUpperCase()).join("")
    if (!key) key = "PRJ"
    const existingKeys = projects.map((p) => p.jiraKey)
    if (!existingKeys.includes(key)) return key
    let i = 2
    while (existingKeys.includes(`${key}${i}`)) i++
    return `${key}${i}`
  }

  function handleAprovar() {
    if (!proposal) return
    const jiraKey = generateJiraKey(empresa)
    const newProject = addProject({
      name: empresa,
      jiraKey,
      status: "Ativo",
      baseConhecimento: [],
    })
    const sanitizedName = empresa.replace(/\s+/g, "_")
    addKnowledgeBaseFile(newProject.id, {
      id: `kb-prop-${Date.now()}`,
      nome: `Proposta_Comercial_${sanitizedName}.pdf`,
      tipo: ".pdf",
      tamanho: "256 KB",
      dataUpload: Date.now(),
      enviadoPor: "João Silva",
      origem: "Proposta Comercial",
      conteudo: JSON.stringify(proposal.proposalContent),
    })
    updateProposal(id, {
      status: "Aprovada",
      projetoGeradoId: newProject.id,
    })
    toast.success(`Proposta aprovada com sucesso! O projeto "${empresa}" foi criado e a proposta adicionada a base de conhecimento.`)
  }

  if (!proposal) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <div className="text-center">
          <p className="text-sm text-muted-foreground">Proposta não encontrada.</p>
          <Button
            variant="link"
            onClick={() => router.push("/dashboard/gerador-de-proposta")}
            className="mt-2 text-primary"
          >
            Voltar para listagem
          </Button>
        </div>
      </div>
    )
  }

  const projetoGerado = proposal.projetoGeradoId
    ? projects.find((p) => p.id === proposal.projetoGeradoId)
    : undefined

  return (
    <div className="flex flex-1 flex-col gap-4 overflow-hidden">
      {/* Top bar with fields */}
      <div className="flex flex-col gap-3">
        {/* Row 1: Para + Empresa + Projeto */}
        <div className="grid grid-cols-1 gap-3 sm:grid-cols-3">
          <div>
            <Label htmlFor="editor-para" className="text-xs font-medium text-muted-foreground">
              Para (Nome do Cliente)
            </Label>
            <Input
              id="editor-para"
              value={para}
              onChange={(e) => updateProposal(id, { para: e.target.value })}
              placeholder="Nome do cliente"
              className="mt-1"
            />
          </div>
          <div>
            <Label htmlFor="editor-empresa" className="text-xs font-medium text-muted-foreground">
              Empresa
            </Label>
            <Input
              id="editor-empresa"
              value={empresa}
              onChange={(e) => updateProposal(id, { empresa: e.target.value })}
              placeholder="Nome da empresa"
              className="mt-1"
            />
          </div>
          <div>
            <Label htmlFor="editor-projeto" className="text-xs font-medium text-muted-foreground">
              Projeto
            </Label>
            <Input
              id="editor-projeto"
              value={projeto}
              onChange={(e) => updateProposal(id, { projeto: e.target.value })}
              placeholder="Nome do projeto"
              className="mt-1"
            />
          </div>
        </div>
        {/* Row 2: Interesse + Modelo */}
        <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
          <div>
            <Label className="text-xs font-medium text-muted-foreground">Interesse</Label>
            <Select
              value={interesse}
              onValueChange={(val) => updateProposal(id, { interesse: val as ProposalInteresse })}
            >
              <SelectTrigger className="mt-1">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {interesseOptions.map((opt) => (
                  <SelectItem key={opt} value={opt}>{opt === "Vazio" ? "Não definido" : opt}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
          <div>
            <Label className="text-xs font-medium text-muted-foreground">Modelo de Trabalho</Label>
            <Select
              value={modeloTrabalho}
              onValueChange={(val) => updateProposal(id, { modeloTrabalho: val as ProposalModelo })}
            >
              <SelectTrigger className="mt-1">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {modeloOptions.map((opt) => (
                  <SelectItem key={opt} value={opt}>{opt === "Vazio" ? "Não definido" : opt}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </div>
      </div>

      {/* Lead link banner */}
      {leadOrigem && (
        <div className="flex items-center gap-3 rounded-lg bg-secondary px-4 py-3">
          <Target className="h-4 w-4 shrink-0 text-primary" />
          <p className="text-sm text-primary">
            {"Esta proposta foi gerada a partir do lead "}
            <strong>{`"${leadOrigem.titulo}"`}</strong>.{" "}
            <Link
              href="/dashboard/leads"
              className="font-medium underline underline-offset-2 hover:text-primary/90"
            >
              Ver Lead
            </Link>
          </p>
        </div>
      )}

      {/* Mobile tab switcher */}
      <div className="flex gap-1 rounded-lg bg-muted p-1 lg:hidden">
        <Button
          variant={activeTab === "chat" ? "secondary" : "ghost"}
          onClick={() => setActiveTab("chat")}
          className={`flex-1 rounded-md px-3 py-1.5 text-sm font-medium ${
            activeTab === "chat"
              ? "bg-card text-foreground shadow-sm"
              : "text-muted-foreground hover:text-foreground"
          }`}
        >
          Assistente
        </Button>
        <Button
          variant={activeTab === "proposta" ? "secondary" : "ghost"}
          onClick={() => setActiveTab("proposta")}
          className={`flex-1 rounded-md px-3 py-1.5 text-sm font-medium ${
            activeTab === "proposta"
              ? "bg-card text-foreground shadow-sm"
              : "text-muted-foreground hover:text-foreground"
          }`}
        >
          Proposta
        </Button>
      </div>

      {/* Desktop: 50/50 split */}
      <div className="flex flex-1 gap-4 overflow-hidden">
        <div
          className={`flex-1 overflow-hidden lg:flex lg:max-w-none ${
            activeTab === "chat" ? "flex" : "hidden lg:flex"
          }`}
          style={{ flex: "1 1 50%" }}
        >
          <div className="flex w-full flex-col overflow-hidden md:flex-[45] lg:flex-[50]">
            <ProposalChatPanel
              messages={proposal.conversationHistory}
              onSendMessage={handleSendMessage}
              isProcessing={isProcessing}
            />
          </div>
        </div>

        <div
          className={`flex-1 overflow-hidden lg:flex lg:max-w-none ${
            activeTab === "proposta" ? "flex" : "hidden lg:flex"
          }`}
          style={{ flex: "1 1 50%" }}
        >
          <div className="flex w-full flex-col overflow-hidden md:flex-[55] lg:flex-[50]">
            <ProposalDocument
              empresa={empresa}
              para={para}
              projeto={projeto}
              proposalNumber={proposal.proposalNumber}
              dataCriacao={proposal.dataCriacao}
              sections={proposal.proposalContent}
              highlightedSections={highlightedSections}
              status={proposal.status}
              interesse={interesse}
              modeloTrabalho={modeloTrabalho}
              projetoGeradoId={proposal.projetoGeradoId}
              projetoGeradoNome={projetoGerado?.name}
              onMarkConcluida={handleMarkConcluida}
              onAprovar={handleAprovar}
            />
          </div>
        </div>
      </div>

