                  <TableHead className="w-[40%]">Distribuicao</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {hoursByUser.map((u) => (
                  <TableRow key={u.name}>
                    <TableCell className="font-medium">
                      <div className="flex items-center gap-2">
                        <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-secondary">
                          <Users className="h-3.5 w-3.5 text-primary" />
                        </div>
                        <span>{u.name}</span>
                      </div>
                    </TableCell>
                    <TableCell className="font-bold">{u.hours}h</TableCell>
                    <TableCell className="text-muted-foreground">
                      <Badge variant="secondary" className="bg-secondary text-primary">
                        {u.projectCount} {u.projectCount === 1 ? "projeto" : "projetos"}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-muted-foreground">
                      <div className="h-2 rounded-full bg-secondary">
                        <div
                          className="h-2 rounded-full bg-primary transition-all"
                          style={{ width: `${(u.hours / maxUserHours) * 100}%` }}
                        />
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

