              className="bg-[#16a34a] text-primary-foreground hover:bg-[#15803d]"
            >
              Aprovar
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  )
